import{_ as t,c as o,o as d,ag as c}from"./chunks/framework.Bw-5EFTY.js";const h=JSON.parse('{"title":"agent-remote-client Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/agent-remote-client/SPEC.md","filePath":"packages/agent-remote-client/SPEC.md"}'),r={name:"packages/agent-remote-client/SPEC.md"};function s(a,e,i,n,l,p){return d(),o("div",null,e[0]||(e[0]=[c('<h1 id="agent-remote-client-specification" tabindex="-1">agent-remote-client Specification <a class="header-anchor" href="#agent-remote-client-specification" aria-label="Permalink to &quot;agent-remote-client Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>Owns the client-side remote execution layer for Robota SDK. Provides <code>RemoteExecutor</code> (implements <code>IExecutor</code>) to proxy AI provider calls to a remote server over HTTP, plus the low-level <code>HttpClient</code> used by the executor. Server-side code has been extracted into separate packages (<code>agent-transport-http</code>, <code>agent-transport-ws</code>) and is no longer part of this package.</p><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li>Does not own core agent/provider contracts (<code>IExecutor</code>, <code>IAIProvider</code>, <code>IAssistantMessage</code>); imports from <code>@robota-sdk/agent-core</code>.</li><li>Does not own server-side hosting logic; that belongs to <code>agent-transport-http</code> and downstream server packages.</li><li>Does not own WebSocket transport; that belongs to <code>agent-transport-ws</code>.</li><li>Has a single production dependency: <code>@robota-sdk/agent-core</code>.</li><li>Package is <code>private: true</code>; it is not published to npm.</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>Single entry point <code>./</code> backed by <code>src/index.ts</code>.</p><p><code>RemoteExecutor</code> (<code>SimpleRemoteExecutor</code>) is the main facade. It composes <code>HttpClient</code> for HTTP communication, validates requests, and maps responses to <code>IAssistantMessage</code> / <code>TUniversalMessage</code>. It implements both <code>executeChat</code> (non-streaming) and <code>executeChatStream</code> (SSE streaming).</p><p><code>HttpClient</code> provides typed <code>post</code>, <code>get</code>, <code>chat</code>, and <code>chatStream</code> methods. It uses the Fetch API and handles SSE frame parsing for streaming responses. It accepts an injected <code>ILogger</code> via <code>IHttpClientConfig</code>.</p><p>Utility functions in <code>src/utils/transformers.ts</code> are pure functions with no side effects. They handle message conversion, request/response construction, and JSON safety.</p><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><p>This package is SSOT for the following types. All types marked <strong>public</strong> are exported from the <code>.</code> entry point; others are internal.</p><ul><li><code>IBasicMessage</code>, <code>IRequestMessage</code>, <code>IResponseMessage</code>, <code>ITokenUsage</code> — message types (<strong>public</strong>).</li><li><code>IHttpRequest</code>, <code>IHttpResponse</code>, <code>IHttpError</code>, <code>THttpMethod</code> — HTTP types (<strong>public</strong>).</li><li><code>ISimpleRemoteConfig</code> — <code>RemoteExecutor</code> constructor configuration (internal).</li><li><code>IHttpClientConfig</code> — <code>HttpClient</code> constructor configuration (internal).</li><li><code>ISimpleExecutionRequest</code> — simplified execution request used by <code>HttpClient.chat</code> / <code>chatStream</code> (internal).</li><li><code>IExtendedAssistantMessage</code> — assistant message extended with provider/model/usage fields (internal).</li><li><code>CommunicationProtocol</code> — protocol enum; currently unused externally but kept as future extension point (internal).</li><li><code>IChatRequestBody</code>, <code>IChatResponseData</code>, <code>ITransportRequest</code>, <code>ITransportResponse</code> — transport payload shapes (internal).</li><li><code>IExtendedChatExecutionRequest</code>, <code>IExtendedStreamExecutionRequest</code> — request extensions with temperature/maxTokens (internal).</li><li><code>IRemoteConfig</code>, <code>IHealthStatus</code>, <code>IUserContext</code>, <code>IProviderStatus</code> — shared configuration/status types (internal).</li></ul><p>Re-exports from <code>@robota-sdk/agent-core</code> via <code>src/shared/types.ts</code> (<code>IExecutor</code>, <code>IChatExecutionRequest</code>, <code>IStreamExecutionRequest</code>, <code>IRemoteExecutorConfig</code>, <code>TUniversalMessage</code>, <code>IAssistantMessage</code>) are compatibility shims and do not represent SSOT ownership.</p><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Description</th></tr></thead><tbody><tr><td><code>RemoteExecutor</code> (<code>SimpleRemoteExecutor</code>)</td><td>class</td><td><code>IExecutor</code> implementation for remote HTTP calls</td></tr><tr><td><code>HttpClient</code></td><td>class</td><td>Low-level HTTP client (chat + streaming)</td></tr><tr><td><code>toRequestMessage</code>, <code>toResponseMessage</code>, <code>createHttpRequest</code>, etc.</td><td>functions</td><td>Pure transformer utilities</td></tr><tr><td><code>IBasicMessage</code>, <code>IRequestMessage</code>, <code>IResponseMessage</code>, <code>ITokenUsage</code></td><td>types</td><td>Message contract types</td></tr><tr><td><code>IHttpRequest</code>, <code>IHttpResponse</code>, <code>IHttpError</code>, <code>THttpMethod</code></td><td>types</td><td>HTTP contract types</td></tr><tr><td><code>IExecutor</code>, <code>IChatExecutionRequest</code>, <code>IStreamExecutionRequest</code>, <code>TUniversalMessage</code>, <code>IAssistantMessage</code>, <code>IRemoteExecutorConfig</code></td><td>types</td><td>Re-exported from <code>@robota-sdk/agent-core</code> for consumer convenience</td></tr></tbody></table><p>Utility functions exported from <code>./utils/transformers</code>: <code>toRequestMessage</code>, <code>toResponseMessage</code>, <code>createHttpRequest</code>, <code>createHttpResponse</code>, <code>extractContent</code>, <code>generateId</code>, <code>normalizeHeaders</code>, <code>safeJsonParse</code>.</p><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><ul><li><code>ISimpleRemoteConfig.logger</code> — inject a custom <code>ILogger</code> into <code>RemoteExecutor</code>.</li><li><code>IHttpClientConfig.logger</code> — inject a custom <code>ILogger</code> into <code>HttpClient</code>.</li><li><code>ISimpleRemoteConfig.headers</code> — pass additional HTTP headers to every request.</li><li><code>ISimpleRemoteConfig.timeout</code> — configure request timeout (default: 30 000 ms).</li></ul><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>Error / Condition</th><th>Trigger</th></tr></thead><tbody><tr><td><code>RemoteExecutor</code></td><td><code>Error(&#39;Messages array is required...&#39;)</code></td><td><code>messages</code> is empty or missing</td></tr><tr><td><code>RemoteExecutor</code></td><td><code>Error(&#39;Provider is required&#39;)</code></td><td><code>request.provider</code> is empty</td></tr><tr><td><code>RemoteExecutor</code></td><td><code>Error(&#39;Model is required&#39;)</code></td><td><code>request.model</code> is empty</td></tr><tr><td><code>RemoteExecutor</code></td><td><code>Error(&#39;BaseURL is required but not provided&#39;)</code></td><td><code>serverUrl</code> missing in config</td></tr><tr><td><code>RemoteExecutor</code></td><td><code>Error(&#39;User API key is required but not provided&#39;)</code></td><td><code>userApiKey</code> missing in config</td></tr><tr><td><code>HttpClient</code></td><td><code>Error(&#39;HTTP &lt;status&gt;: &lt;text&gt;&#39;)</code></td><td>Non-2xx HTTP response</td></tr><tr><td><code>HttpClient</code></td><td><code>Error(&#39;No response body for streaming&#39;)</code></td><td>Streaming response has no body</td></tr><tr><td><code>HttpClient</code></td><td><code>Error(&#39;Streaming request failed: ...&#39;)</code></td><td>Unhandled error during SSE read loop</td></tr><tr><td><code>HttpClient</code></td><td><code>Error(&#39;Request failed: ...&#39;)</code></td><td>Unhandled error in <code>executeRequest</code></td></tr></tbody></table><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><h3 id="interface-implementations" tabindex="-1">Interface Implementations <a class="header-anchor" href="#interface-implementations" aria-label="Permalink to &quot;Interface Implementations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Interface</th><th>Implementor</th><th>Location</th></tr></thead><tbody><tr><td><code>IExecutor</code> (core)</td><td><code>SimpleRemoteExecutor</code></td><td><code>src/client/remote-executor-simple.ts</code></td></tr></tbody></table><h3 id="cross-package-port-consumers" tabindex="-1">Cross-Package Port Consumers <a class="header-anchor" href="#cross-package-port-consumers" aria-label="Permalink to &quot;Cross-Package Port Consumers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Port (Owner)</th><th>Adapter</th><th>Location</th></tr></thead><tbody><tr><td><code>IExecutor</code> (core)</td><td><code>SimpleRemoteExecutor</code></td><td><code>src/client/remote-executor-simple.ts</code></td></tr><tr><td><code>ILogger</code> (core)</td><td><code>SimpleRemoteExecutor</code></td><td><code>src/client/remote-executor-simple.ts</code></td></tr><tr><td><code>ILogger</code> (core)</td><td><code>HttpClient</code></td><td><code>src/client/http-client.ts</code></td></tr></tbody></table><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><ul><li><strong>Unit tests</strong>: 7 test files covering client and utilities: <ul><li><code>src/client/__tests__/http-client.test.ts</code> — <code>HttpClient</code> request/response handling</li><li><code>src/client/__tests__/http-client-chat.test.ts</code> — <code>HttpClient.chat</code> payload mapping</li><li><code>src/client/__tests__/remote-executor-simple.test.ts</code> — <code>RemoteExecutor</code> validation and execution</li><li><code>src/client/__tests__/request-handler-simple.test.ts</code> — request handler helpers</li><li><code>src/shared/__tests__/types.test.ts</code> — shared type validation</li><li><code>src/utils/__tests__/transformers.test.ts</code> — pure transformer functions</li><li><code>src/__tests__/exports.test.ts</code> — public entry point export surface</li></ul></li><li><strong>Coverage gap</strong>: SSE streaming paths have limited coverage.</li></ul>',28)]))}const m=t(r,[["render",s]]);export{h as __pageData,m as default};
